mapper.select:
select o.*, s.name as shopName from orders o
left join shop s on o.shop_id = s.id
where o.id = #{id}

select o.*, s.name as shopName from orders o
left join shop s on o.shop_id = s.id


        and o.order_no like concat('%', #{orderNo}, '%')


        and o.user_id = #{userId}


        and o.shop_id = #{shopId}


        and o.total_amount = #{totalAmount}


        and o.pay_amount = #{payAmount}


        and o.delivery_fee = #{deliveryFee}


        and o.remark like concat('%', #{remark}, '%')


        and o.status = #{status}


        and o.receiver_name like concat('%', #{receiverName}, '%')


        and o.receiver_phone like concat('%', #{receiverPhone}, '%')


        and o.receiver_address like concat('%', #{receiverAddress}, '%')


        and o.pay_time = #{payTime}


        and o.delivery_time = #{deliveryTime}


        and o.finish_time = #{finishTime}


        and o.create_time = #{createTime}


        and o.update_time = #{updateTime}


order by o.id desc
